int state_machine(int event, int state) {
    // Simple state machine: int event, int state, 3=ERROR
    switch (state) {
        case 0:  // Idle
            if (event == 1) return 1;  // Start processing
            return 0;
        case 1:  // 
            if
            if (event == 2) return 2;  // Complete
            else if (event == 99) return 3;  // Error
            break;
        case 2:  // Done
            return 2;
            break;
        case 3:  //
            if (event == 0) return 0;  // Error reset
            return 3;
            break;
        default:
            return 3;  // Unknown status transition error
    }
}

