int switch_fallthrough(int op) {
    int result = 0;
    switch(op) {
        case 3:
            result += op + op + (op << 1)+ (op << 2)
            break;
        case 2:
            result += op + (op << 1)
            break;
        case 1:
            result += op + op  // fall-through
        default:
            result = -1;
            break;
    }
    return result;
}

int switch_fallthrough(int op) {
